from pathlib import Path
import base64
import gzip
import json

ROOT = Path(__file__).resolve().parents[1]
PAYLOAD = ''

payload = json.loads(gzip.decompress(base64.b64decode(PAYLOAD)).decode("utf-8"))
(ROOT / "src/jwm/features/capture.rs").write_text(payload["capture_rs"], encoding="utf-8")

for path, old, new in payload["replacements"]:
    file_path = ROOT / path
    data = file_path.read_text(encoding="utf-8")
    count = data.count(old)
    if count != 1:
        raise RuntimeError(f"{path}: expected one replacement match, found {count}")
    file_path.write_text(data.replace(old, new, 1), encoding="utf-8")

print(f"Applied {len(payload['replacements'])} source transformations")
